"use client";

import * as React from "react";
import { MoreHorizontal } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

export interface ScreenRow {
  _id: string;
  screen_name: string;
  status: string;
  connected: boolean;
  ad_serving_mode: string;
  playlist_name: string | null;
}

export interface LocationGroup {
  location_id: string;
  location_name: string;
  screens: ScreenRow[];
}

interface ScreensPageProps {
  locationGroups: LocationGroup[];
}

export function ScreensPage({ locationGroups }: ScreensPageProps) {
  if (locationGroups.length === 0) {
    return (
      <div className="flex flex-1 flex-col items-center justify-center py-24">
        <p className="text-muted-foreground text-sm">No screens found.</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-8 pt-4">
      <h1 className="text-xl font-semibold">Screens</h1>
      {locationGroups.map((group) => (
        <LocationSection key={group.location_id} group={group} />
      ))}
    </div>
  );
}

function LocationSection({ group }: { group: LocationGroup }) {
  return (
    <div className="flex flex-col gap-3">
      <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wide">
        {group.location_name}
      </h2>
      <div className="rounded-md border">
        <table className="w-full text-sm">
          <thead>
            <tr className="border-b bg-muted/50">
              <th className="px-4 py-3 text-left font-medium text-muted-foreground">Screen Name</th>
              <th className="px-4 py-3 text-left font-medium text-muted-foreground">Status</th>
              <th className="px-4 py-3 text-left font-medium text-muted-foreground">Connected</th>
              <th className="px-4 py-3 text-left font-medium text-muted-foreground">Ad Serving</th>
              <th className="px-4 py-3 text-left font-medium text-muted-foreground">Playlist</th>
              <th className="px-4 py-3 text-right font-medium text-muted-foreground"></th>
            </tr>
          </thead>
          <tbody>
            {group.screens.map((screen, index) => (
              <ScreenRow
                key={screen._id}
                screen={screen}
                isLast={index === group.screens.length - 1}
              />
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function ScreenRow({ screen, isLast }: { screen: ScreenRow; isLast: boolean }) {
  return (
    <tr className={isLast ? "" : "border-b"}>
      <td className="px-4 py-3 font-medium">{screen.screen_name}</td>
      <td className="px-4 py-3">
        <StatusBadge status={screen.status} />
      </td>
      <td className="px-4 py-3">
        <ConnectedBadge connected={screen.connected} />
      </td>
      <td className="px-4 py-3 text-muted-foreground">
        {screen.ad_serving_mode === "ad-free" ? "Ad Free" : "Ad Supported"}
      </td>
      <td className="px-4 py-3 text-muted-foreground">
        {screen.playlist_name ?? <span className="text-muted-foreground/50">—</span>}
      </td>
      <td className="px-4 py-3 text-right">
        <ScreenMenu screen={screen} />
      </td>
    </tr>
  );
}

function StatusBadge({ status }: { status: string }) {
  if (status === "active") {
    return <Badge className="bg-green-100 text-green-800 hover:bg-green-100">Active</Badge>;
  }
  if (status === "new") {
    return <Badge variant="secondary">New</Badge>;
  }
  return <Badge variant="outline">{status}</Badge>;
}

function ConnectedBadge({ connected }: { connected: boolean }) {
  if (connected) {
    return <Badge className="bg-green-100 text-green-800 hover:bg-green-100">Online</Badge>;
  }
  return <Badge variant="secondary">Offline</Badge>;
}

function ScreenMenu({ screen }: { screen: ScreenRow }) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="sm" className="h-7 w-7 p-0">
          <MoreHorizontal className="size-4" />
          <span className="sr-only">Open menu</span>
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        {screen.status === "new" && (
          <DropdownMenuItem>Install</DropdownMenuItem>
        )}
        {screen.status === "active" && (
          <>
            <DropdownMenuItem>Edit</DropdownMenuItem>
            <DropdownMenuItem>Set Playlist</DropdownMenuItem>
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}
